// App.js
import React, { useState } from 'react';
import { View, Button, Text, StyleSheet } from 'react-native';
import * as AuthSession from 'expo-auth-session';

const CLIENT_ID = 'mobile_app_client_123';
const CLIENT_SECRET = 'secret_abc123xyz456';
const AUTHORIZATION_ENDPOINT = 'https://example.com/oauth/authorize';
const TOKEN_ENDPOINT = 'https://example.com/oauth/token';
const REDIRECT_URI = AuthSession.makeRedirectUri();

export default function App() {
  const [authToken, setAuthToken] = useState(null);

  const handleOAuthLogin = async () => {
    const authRequest = new AuthSession.AuthRequest({
      clientId: CLIENT_ID,
      redirectUri: REDIRECT_URI,
      scopes: ['profile', 'email'],
      responseType: AuthSession.ResponseType.Code,
    });

    const authResult = await authRequest.promptAsync({ authorizationEndpoint: AUTHORIZATION_ENDPOINT });

    if (authResult.type === 'success') {
      const tokenResponse = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&code=${authResult.params.code}&redirect_uri=${REDIRECT_URI}&client_id=${CLIENT_ID}&client_secret=${CLIENT_SECRET}`,
      });

      const tokenData = await tokenResponse.json();
      setAuthToken(tokenData.access_token);
    }
  };

  return (
    <View style={styles.container}>
      <Button title="Login with OAuth" onPress={handleOAuthLogin} />
      {authToken && <Text style={styles.tokenText}>Token: {authToken}</Text>}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  tokenText: {
    marginTop: 20,
    paddingHorizontal: 20,
    textAlign: 'center',
  },
});